BEGIN;
SET client_min_messages TO WARNING;
DROP SCHEMA IF EXISTS "alien" CASCADE;
CREATE SCHEMA IF NOT EXISTS "alien";

DROP TABLE IF EXISTS "alien"."observationalconditions" CASCADE;
CREATE TABLE "alien"."observationalconditions" ("signalref" TEXT, "obstime" TEXT, "obsdate" TEXT, "obsdurhrs" DOUBLE PRECISION);

DROP TABLE IF EXISTS "alien"."observatories" CASCADE;
CREATE TABLE "alien"."observatories" ("observstation" TEXT, "weathprofile" TEXT, "seeingprofile" TEXT, "atmostransparency" DOUBLE PRECISION, "lunarstage" TEXT, "lunardistdeg" DOUBLE PRECISION, "solarstatus" TEXT, "geomagstatus" TEXT, "sidereallocal" TEXT, "airtempc" DOUBLE PRECISION, "humidityrate" DOUBLE PRECISION, "windspeedms" DOUBLE PRECISION, "presshpa" DOUBLE PRECISION);

DROP TABLE IF EXISTS "alien"."researchprocess" CASCADE;
CREATE TABLE "alien"."researchprocess" ("signalref" TEXT, "analysisprio" TEXT, "followstat" TEXT, "peerrevstat" TEXT, "pubstat" TEXT, "resprio" TEXT, "fundstat" TEXT, "collabstat" TEXT, "secclass" TEXT, "discstat" TEXT, "notesmemo" TEXT);

DROP TABLE IF EXISTS "alien"."signaladvancedphenomena" CASCADE;
CREATE TABLE "alien"."signaladvancedphenomena" ("signalref" TEXT, "intermedeffects" TEXT, "gravlens" TEXT, "quanteffects" TEXT, "encryptevid" TEXT, "langstruct" TEXT, "msgcontent" TEXT, "cultsig" TEXT, "sciimpact" TEXT);

DROP TABLE IF EXISTS "alien"."signalclassification" CASCADE;
CREATE TABLE "alien"."signalclassification" ("signalref" TEXT, "sigclasstype" TEXT, "sigpattern" TEXT, "repeatcount" BIGINT, "periodsec" DOUBLE PRECISION, "complexidx" DOUBLE PRECISION, "entropyval" DOUBLE PRECISION, "infodense" DOUBLE PRECISION, "classconf" DOUBLE PRECISION);

DROP TABLE IF EXISTS "alien"."signaldecoding" CASCADE;
CREATE TABLE "alien"."signaldecoding" ("signalref" TEXT, "encodetype" TEXT, "compressratio" DOUBLE PRECISION, "errcorrlvl" TEXT, "decodeconf" DOUBLE PRECISION, "decodemethod" TEXT, "decodestat" TEXT, "decodeiters" BIGINT, "proctimehrs" DOUBLE PRECISION, "compresources" TEXT, "analysisdp" TEXT, "veriflvl" TEXT, "confirmstat" TEXT);

DROP TABLE IF EXISTS "alien"."signaldynamics" CASCADE;
CREATE TABLE "alien"."signaldynamics" ("signalref" TEXT, "sigintegrity" TEXT, "sigrecurr" TEXT, "sigevolve" TEXT, "tempstab" TEXT, "spatstab" TEXT, "freqstab" TEXT, "phasestab" TEXT, "ampstab" TEXT, "modstab" TEXT, "sigcoherence" TEXT, "sigdisp" TEXT, "sigscint" TEXT);

DROP TABLE IF EXISTS "alien"."signalprobabilities" CASCADE;
CREATE TABLE "alien"."signalprobabilities" ("signalref" TEXT, "falseposprob" DOUBLE PRECISION, "sigunique" DOUBLE PRECISION, "simindex" DOUBLE PRECISION, "corrscore" DOUBLE PRECISION, "anomscore" BIGINT, "techsigprob" DOUBLE PRECISION, "biosigprob" DOUBLE PRECISION, "natsrcprob" DOUBLE PRECISION, "artsrcprob" DOUBLE PRECISION);

DROP TABLE IF EXISTS "alien"."signals" CASCADE;
CREATE TABLE "alien"."signals" ("signalregistry" TEXT, "timemark" TEXT, "telescref" TEXT, "detectinstr" TEXT, "signalclass" TEXT, "sigstrdb" DOUBLE PRECISION, "freqmhz" DOUBLE PRECISION, "bwhz" DOUBLE PRECISION, "centerfreqmhz" DOUBLE PRECISION, "freqdrifthzs" DOUBLE PRECISION, "doppshifthz" BIGINT, "sigdursec" DOUBLE PRECISION, "pulsepersec" DOUBLE PRECISION, "pulsewidms" DOUBLE PRECISION, "modtype" TEXT, "modindex" DOUBLE PRECISION, "carrierfreqmhz" DOUBLE PRECISION, "phaseshiftdeg" DOUBLE PRECISION, "polarmode" TEXT, "polarangledeg" DOUBLE PRECISION, "snrratio" DOUBLE PRECISION, "noisefloordbm" BIGINT, "interflvl" TEXT, "rfistat" TEXT, "atmointerf" TEXT);

DROP TABLE IF EXISTS "alien"."sourceproperties" CASCADE;
CREATE TABLE "alien"."sourceproperties" ("signalref" TEXT, "sourceradeg" DOUBLE PRECISION, "sourcedecdeg" DOUBLE PRECISION, "sourcedistly" DOUBLE PRECISION, "gallong" DOUBLE PRECISION, "gallat" DOUBLE PRECISION, "celestobj" TEXT, "objtype" TEXT, "objmag" DOUBLE PRECISION, "objtempk" BIGINT, "objmasssol" DOUBLE PRECISION, "objagegyr" DOUBLE PRECISION, "objmetal" DOUBLE PRECISION, "objpropmotion" DOUBLE PRECISION, "objradvel" DOUBLE PRECISION);

DROP TABLE IF EXISTS "alien"."telescopes" CASCADE;
CREATE TABLE "alien"."telescopes" ("telescregistry" TEXT, "observstation" TEXT, "equipstatus" TEXT, "calibrstatus" TEXT, "pointaccarc" DOUBLE PRECISION, "trackaccarc" DOUBLE PRECISION, "focusquality" TEXT, "detecttempk" DOUBLE PRECISION, "coolsysstatus" TEXT, "powerstatus" TEXT, "datastorstatus" TEXT, "netstatus" TEXT, "bandusagepct" DOUBLE PRECISION, "procqueuestatus" TEXT);

COMMIT;
